const p = ($json.body) || {};
const grade = Number(p.grade || 6);
const prevGrade = Math.max(1, grade - 1);
const system = [
  'You are Sheldon, an expert tutor and curriculum specialist for Super Sheldon EdTech. You generate diagnostic tests that identify learning gaps.',
  '',
  'Rules:',
  '- The test covers the PREVIOUS year syllabus (Grade ' + prevGrade + ') to surface gaps.',
  '- Match the region curriculum: UK National, Australia ACARA V9, India CBSE, USA Common Core, Singapore MOE, NZ NZC.',
  '- Each question targets ONE skill. Distribute across 4-5 distinct skills.',
  '- Difficulty mix: 30% easy, 50% medium, 20% hard.',
  '- 4 options per question, exactly ONE correct. Wrong answers reflect common mistakes.',
  '',
  'Return ONLY valid JSON. No prose before or after. Shape:',
  '{ "questions": [ { "id": "q1", "text": "...", "options": ["A","B","C","D"], "correctIndex": 0, "skill": "Fractions" } ] }'
].join('\n');
const user = [
  'Generate a ' + (p.numQuestions || 10) + '-question diagnostic test for:',
  'Student: ' + (p.name || 'Student') + ', Grade ' + grade + ', ' + (p.region || 'UK') + ', Subject: ' + (p.subject || 'Maths'),
  'Parent goal: ' + (p.goal || 'Curriculum Alignment'),
  '',
  'Test the PREVIOUS year content (Grade ' + prevGrade + ').'
].join('\n');
return [{ json: { system: system, user: user, _payload: p, _kind: 'diagnostic-generate' } }];

const data = $json;
let text = '', provider = 'unknown', model = '';
if (data && data.content && data.content[0] && data.content[0].text) { text = data.content[0].text; provider = 'claude'; model = data.model || ''; }
else if (data && data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content) { text = data.choices[0].message.content; provider = 'hf'; model = data.model || ''; }
else { throw new Error('Unrecognized LLM response: ' + JSON.stringify(data).slice(0, 300)); }
let jsonStr = text.replace(/^[^{\[]*/, '').trim();
const start = jsonStr.indexOf('{');
const end = jsonStr.lastIndexOf('}');
if (start === -1 || end === -1) throw new Error('No JSON in response: ' + text.slice(0, 200));
let parsed;
try { parsed = JSON.parse(jsonStr.slice(start, end + 1)); } catch (e) { throw new Error('JSON parse failed: ' + e.message); }
parsed.quizId = 'q_' + Date.now();
parsed._provider = provider;
parsed._model = model;
return [{ json: parsed }];

const p = ($json.body) || {};
const questions = Array.isArray(p.questions) ? p.questions : [];
const answers = Array.isArray(p.answers) ? p.answers : [];
const byId = Object.fromEntries(answers.map(a => [a.questionId, a.chosenIndex]));
const skillCounts = {};
let correct = 0;
for (const q of questions) {
  const skill = q.skill || 'General';
  skillCounts[skill] = skillCounts[skill] || { correct: 0, total: 0 };
  skillCounts[skill].total += 1;
  const c = byId[q.id];
  if (c !== undefined && c === q.correctIndex) { correct += 1; skillCounts[skill].correct += 1; }
}
const total = Math.max(1, questions.length);
const score = Math.round((correct / total) * 100);
const skills = {};
Object.entries(skillCounts).forEach(([k, v]) => { skills[k] = Math.round((v.correct / Math.max(1, v.total)) * 100); });
const skillsLine = Object.entries(skills).map(([k, v]) => k + ': ' + v + '%').join(', ');
const system = [
  'You are Sheldon, analysing a diagnostic test result for the parent and tutor.',
  '',
  'Given per-skill scores, write:',
  '- 2-3 STRENGTHS (specific, encouraging, max 12 words each)',
  '- 2-3 WEAKNESSES (specific but kind. Never use "weak" or "bad". Say "needs more practice with...")',
  '- 3-4 RECOMMENDATIONS (concrete, time-bounded, max 15 words each)',
  '- One ANALYSIS paragraph (3-4 sentences, warm tutor voice, references actual skills/scores)',
  '',
  'Return ONLY valid JSON. No prose before or after. Shape:',
  '{ "strengths": ["..."], "weaknesses": ["..."], "recommendations": ["..."], "analysisText": "..." }'
].join('\n');
const user = [
  'Quiz id: ' + (p.quizId || ''),
  'Overall score: ' + score + '% (' + correct + '/' + total + ')',
  'Per-skill scores: ' + skillsLine
].join('\n');
return [{ json: { system: system, user: user, _score: score, _skills: skills, _kind: 'diagnostic-analyze' } }];

